// app/page.tsx
import { revalidateTag } from 'next/cache';
import { getCachedProducts } from '../lib/db';

export const dynamic = 'force-dynamic';

export default async function Page() {
  const products = await getCachedProducts();

  async function syncLatestCatalog() {
    'use server';

    revalidateTag('products', 'max');
  }

  return (
    <main className="catalog-page">
      <section className="catalog-shell">
        <header className="catalog-header">
          <div>
            <p className="eyebrow">Admin catalog</p>
            <h1>Product catalog</h1>
            <p className="lede">
              Browse catalog data quickly. Syncing marks the shared <code>products</code> cache stale and refreshes it in the background.
            </p>
          </div>

          <form action={syncLatestCatalog}>
            <button type="submit" className="sync-button">
              Sync latest catalog
            </button>
          </form>
        </header>

        <section className="status-strip" aria-label="Catalog status">
          <div>
            <span className="status-label">Cache tag</span>
            <strong>products</strong>
          </div>
          <div>
            <span className="status-label">Refresh mode</span>
            <strong>Stale while revalidate</strong>
          </div>
          <div>
            <span className="status-label">Source</span>
            <strong>ERP / PIM feed</strong>
          </div>
        </section>

        <section className="table-card" aria-label="Products">
          <table>
            <thead>
              <tr>
                <th>SKU</th>
                <th>Product</th>
                <th>Price</th>
                <th>Inventory</th>
                <th>Availability</th>
              </tr>
            </thead>
            <tbody>
              {products.map(product => (
                <tr key={product.id}>
                  <td data-label="SKU">{String(product.id).padStart(4, '0')}</td>
                  <td data-label="Product">{product.name}</td>
                  <td data-label="Price">${product.price.toLocaleString()}</td>
                  <td data-label="Inventory">{product.inventory}</td>
                  <td data-label="Availability">{product.availability}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </section>
      </section>
    </main>
  );
}


